# 365 Daily Verses - One for each day of the year
# Format: {"reference": "Book Chapter:Verse", "it": "Italian text", "en": "English text", "es": "Spanish text"}

DAILY_VERSES_365 = [
    # Gennaio (1-31)
    {"reference": "Salmi 118:24", "it": "Questo è il giorno che il SIGNORE ha fatto; rallegriamoci e gioisamo in esso.", "en": "This is the day that the LORD has made; let us rejoice and be glad in it.", "es": "Este es el día que hizo el SEÑOR; nos gozaremos y alegraremos en él."},
    {"reference": "Proverbi 3:5-6", "it": "Confida nel SIGNORE con tutto il cuore e non ti appoggiare sul tuo discernimento.", "en": "Trust in the LORD with all your heart, and do not lean on your own understanding.", "es": "Confía en el SEÑOR con todo tu corazón, y no te apoyes en tu propia prudencia."},
    {"reference": "Isaia 41:10", "it": "Non temere, perché io sono con te; non ti smarrire, perché io sono il tuo Dio.", "en": "Fear not, for I am with you; be not dismayed, for I am your God.", "es": "No temas, porque yo estoy contigo; no desmayes, porque yo soy tu Dios."},
    {"reference": "Filippesi 4:13", "it": "Io posso ogni cosa in colui che mi fortifica.", "en": "I can do all things through him who strengthens me.", "es": "Todo lo puedo en Cristo que me fortalece."},
    {"reference": "Romani 8:28", "it": "Tutte le cose cooperano al bene di quelli che amano Dio.", "en": "All things work together for good for those who love God.", "es": "A los que aman a Dios, todas las cosas les ayudan a bien."},
    {"reference": "Geremia 29:11", "it": "Io conosco i pensieri che medito per voi, dice il SIGNORE: pensieri di pace.", "en": "For I know the plans I have for you, declares the LORD, plans for welfare.", "es": "Yo sé los pensamientos que tengo acerca de vosotros, pensamientos de paz."},
    {"reference": "Salmi 23:1", "it": "Il SIGNORE è il mio pastore: nulla mi manca.", "en": "The LORD is my shepherd; I shall not want.", "es": "Jehová es mi pastor; nada me faltará."},
    {"reference": "Giovanni 3:16", "it": "Dio ha tanto amato il mondo, che ha dato il suo unigenito Figlio.", "en": "For God so loved the world, that he gave his only Son.", "es": "Porque de tal manera amó Dios al mundo, que ha dado a su Hijo unigénito."},
    {"reference": "Matteo 11:28", "it": "Venite a me, voi tutti che siete affaticati e oppressi, e io vi darò riposo.", "en": "Come to me, all who labor and are heavy laden, and I will give you rest.", "es": "Venid a mí todos los que estáis trabajados y cargados, y yo os haré descansar."},
    {"reference": "Salmi 46:1", "it": "Dio è per noi un rifugio e una forza, un aiuto sempre pronto nelle difficoltà.", "en": "God is our refuge and strength, a very present help in trouble.", "es": "Dios es nuestro amparo y fortaleza, nuestro pronto auxilio en las tribulaciones."},
    {"reference": "Isaia 40:31", "it": "Quelli che sperano nel SIGNORE acquistano nuove forze.", "en": "They who wait for the LORD shall renew their strength.", "es": "Los que esperan a Jehová tendrán nuevas fuerzas."},
    {"reference": "Salmi 27:1", "it": "Il SIGNORE è la mia luce e la mia salvezza; di chi temerò?", "en": "The LORD is my light and my salvation; whom shall I fear?", "es": "Jehová es mi luz y mi salvación; ¿de quién temeré?"},
    {"reference": "2 Corinzi 5:17", "it": "Se uno è in Cristo, egli è una nuova creatura.", "en": "If anyone is in Christ, he is a new creation.", "es": "Si alguno está en Cristo, nueva criatura es."},
    {"reference": "Romani 12:2", "it": "Non conformatevi a questo mondo, ma siate trasformati.", "en": "Do not be conformed to this world, but be transformed.", "es": "No os conforméis a este siglo, sino transformaos."},
    {"reference": "Efesini 2:8-9", "it": "È per grazia che siete stati salvati, mediante la fede.", "en": "For by grace you have been saved through faith.", "es": "Porque por gracia sois salvos por medio de la fe."},
    {"reference": "Giosuè 1:9", "it": "Sii forte e coraggioso; il SIGNORE tuo Dio sarà con te.", "en": "Be strong and courageous; the LORD your God is with you.", "es": "Esfuérzate y sé valiente; Jehová tu Dios estará contigo."},
    {"reference": "Salmi 34:8", "it": "Gustate e vedete quanto il SIGNORE è buono!", "en": "Oh, taste and see that the LORD is good!", "es": "Gustad, y ved que es bueno Jehová."},
    {"reference": "1 Giovanni 4:19", "it": "Noi amiamo perché egli ci ha amati per primo.", "en": "We love because he first loved us.", "es": "Nosotros le amamos a él, porque él nos amó primero."},
    {"reference": "Galati 5:22-23", "it": "Il frutto dello Spirito è amore, gioia, pace, pazienza, benevolenza.", "en": "The fruit of the Spirit is love, joy, peace, patience, kindness.", "es": "El fruto del Espíritu es amor, gozo, paz, paciencia, benignidad."},
    {"reference": "Salmi 37:4", "it": "Trova la tua gioia nel SIGNORE ed egli appagherà i desideri del tuo cuore.", "en": "Delight yourself in the LORD, and he will give you the desires of your heart.", "es": "Deléitate en Jehová, y él te concederá las peticiones de tu corazón."},
    {"reference": "1 Pietro 5:7", "it": "Gettando su di lui ogni vostra preoccupazione, perché egli ha cura di voi.", "en": "Casting all your anxieties on him, because he cares for you.", "es": "Echando toda vuestra ansiedad sobre él, porque él tiene cuidado de vosotros."},
    {"reference": "Matteo 6:33", "it": "Cercate prima il regno di Dio e la sua giustizia.", "en": "Seek first the kingdom of God and his righteousness.", "es": "Buscad primeramente el reino de Dios y su justicia."},
    {"reference": "Salmi 91:1-2", "it": "Chi abita al riparo dell'Altissimo riposa all'ombra dell'Onnipotente.", "en": "He who dwells in the shelter of the Most High will abide in the shadow of the Almighty.", "es": "El que habita al abrigo del Altísimo morará bajo la sombra del Omnipotente."},
    {"reference": "Giovanni 14:6", "it": "Io sono la via, la verità e la vita.", "en": "I am the way, and the truth, and the life.", "es": "Yo soy el camino, y la verdad, y la vida."},
    {"reference": "Romani 5:8", "it": "Mentre eravamo ancora peccatori, Cristo è morto per noi.", "en": "While we were still sinners, Christ died for us.", "es": "Siendo aún pecadores, Cristo murió por nosotros."},
    {"reference": "Ebrei 11:1", "it": "La fede è certezza di cose che si sperano.", "en": "Faith is the assurance of things hoped for.", "es": "La fe es la certeza de lo que se espera."},
    {"reference": "Salmi 119:105", "it": "La tua parola è una lampada al mio piede e una luce sul mio sentiero.", "en": "Your word is a lamp to my feet and a light to my path.", "es": "Lámpara es a mis pies tu palabra, y lumbrera a mi camino."},
    {"reference": "Giacomo 1:5", "it": "Se qualcuno manca di sapienza, la chieda a Dio.", "en": "If any of you lacks wisdom, let him ask God.", "es": "Si alguno tiene falta de sabiduría, pídala a Dios."},
    {"reference": "Lamentazioni 3:22-23", "it": "Le compassioni del SIGNORE si rinnovano ogni mattina.", "en": "His mercies are new every morning.", "es": "Nuevas son cada mañana sus misericordias."},
    {"reference": "Salmi 139:14", "it": "Sono stato fatto in modo stupendo.", "en": "I am fearfully and wonderfully made.", "es": "Formidables, maravillosas son tus obras."},
    {"reference": "1 Corinzi 10:13", "it": "Dio è fedele e non permetterà che siate tentati oltre le vostre forze.", "en": "God is faithful, and he will not let you be tempted beyond your ability.", "es": "Fiel es Dios, que no os dejará ser tentados más de lo que podéis resistir."},
    # Febbraio (32-59)
    {"reference": "Salmi 103:1", "it": "Benedici, anima mia, il SIGNORE.", "en": "Bless the LORD, O my soul.", "es": "Bendice, alma mía, a Jehová."},
    {"reference": "Giovanni 15:5", "it": "Io sono la vite, voi siete i tralci.", "en": "I am the vine; you are the branches.", "es": "Yo soy la vid, vosotros los pámpanos."},
    {"reference": "Matteo 5:14-16", "it": "Voi siete la luce del mondo.", "en": "You are the light of the world.", "es": "Vosotros sois la luz del mundo."},
    {"reference": "Salmi 55:22", "it": "Getta sul SIGNORE il tuo affanno, ed egli ti sosterrà.", "en": "Cast your burden on the LORD, and he will sustain you.", "es": "Echa sobre Jehová tu carga, y él te sustentará."},
    {"reference": "2 Timoteo 1:7", "it": "Dio ci ha dato uno spirito di forza, di amore e di autocontrollo.", "en": "God gave us a spirit of power and love and self-control.", "es": "No nos ha dado Dios espíritu de cobardía, sino de poder, de amor y de dominio propio."},
    {"reference": "Colossesi 3:23", "it": "Qualunque cosa facciate, fatela di buon animo, come per il Signore.", "en": "Whatever you do, work heartily, as for the Lord.", "es": "Todo lo que hagáis, hacedlo de corazón, como para el Señor."},
    {"reference": "Salmi 121:1-2", "it": "Il mio aiuto viene dal SIGNORE, che ha fatto il cielo e la terra.", "en": "My help comes from the LORD, who made heaven and earth.", "es": "Mi socorro viene de Jehová, que hizo los cielos y la tierra."},
    {"reference": "1 Tessalonicesi 5:16-18", "it": "Siate sempre gioiosi; pregate incessantemente.", "en": "Rejoice always, pray without ceasing.", "es": "Estad siempre gozosos. Orad sin cesar."},
    {"reference": "Giovanni 8:32", "it": "Conoscerete la verità e la verità vi farà liberi.", "en": "You will know the truth, and the truth will set you free.", "es": "Conoceréis la verdad, y la verdad os hará libres."},
    {"reference": "Salmi 100:4-5", "it": "Entrate nelle sue porte con ringraziamento.", "en": "Enter his gates with thanksgiving.", "es": "Entrad por sus puertas con acción de gracias."},
    {"reference": "Ebrei 12:2", "it": "Fissando lo sguardo su Gesù, colui che crea la fede.", "en": "Looking to Jesus, the founder and perfecter of our faith.", "es": "Puestos los ojos en Jesús, el autor y consumador de la fe."},
    {"reference": "1 Giovanni 1:9", "it": "Se confessiamo i nostri peccati, egli è fedele e giusto da perdonarci.", "en": "If we confess our sins, he is faithful to forgive us.", "es": "Si confesamos nuestros pecados, él es fiel y justo para perdonar."},
    {"reference": "Proverbi 16:3", "it": "Affida al SIGNORE le tue opere, e i tuoi progetti avranno successo.", "en": "Commit your work to the LORD, and your plans will be established.", "es": "Encomienda a Jehová tus obras, y tus pensamientos serán afirmados."},
    {"reference": "Matteo 7:7", "it": "Chiedete e vi sarà dato; cercate e troverete.", "en": "Ask, and it will be given to you; seek, and you will find.", "es": "Pedid, y se os dará; buscad, y hallaréis."},
    {"reference": "Salmi 51:10", "it": "O Dio, crea in me un cuore puro.", "en": "Create in me a clean heart, O God.", "es": "Crea en mí, oh Dios, un corazón limpio."},
    {"reference": "Giovanni 16:33", "it": "Nel mondo avrete tribolazione; ma fatevi coraggio, io ho vinto il mondo.", "en": "In the world you will have tribulation. But take heart; I have overcome the world.", "es": "En el mundo tendréis aflicción; pero confiad, yo he vencido al mundo."},
    {"reference": "Romani 15:13", "it": "Il Dio della speranza vi riempia di ogni gioia e pace.", "en": "May the God of hope fill you with all joy and peace.", "es": "El Dios de esperanza os llene de todo gozo y paz."},
    {"reference": "Salmi 145:18", "it": "Il SIGNORE è vicino a tutti quelli che lo invocano.", "en": "The LORD is near to all who call on him.", "es": "Cercano está Jehová a todos los que le invocan."},
    {"reference": "Proverbi 18:10", "it": "Il nome del SIGNORE è una forte torre; il giusto vi corre e vi trova un alto rifugio.", "en": "The name of the LORD is a strong tower; the righteous man runs into it and is safe.", "es": "Torre fuerte es el nombre de Jehová; a él correrá el justo, y será levantado."},
    {"reference": "Isaia 26:3", "it": "Tu conserverai in perfetta pace la mente che è ferma in te.", "en": "You keep him in perfect peace whose mind is stayed on you.", "es": "Tú guardarás en completa paz a aquel cuyo pensamiento en ti persevera."},
    {"reference": "Matteo 28:20", "it": "Ecco, io sono con voi tutti i giorni, fino alla fine dell'età presente.", "en": "Behold, I am with you always, to the end of the age.", "es": "He aquí yo estoy con vosotros todos los días, hasta el fin del mundo."},
    {"reference": "Salmi 62:1-2", "it": "Solo in Dio trova riposo l'anima mia; da lui proviene la mia salvezza.", "en": "For God alone my soul waits in silence; from him comes my salvation.", "es": "En Dios solamente está acallada mi alma; de él viene mi salvación."},
    {"reference": "2 Corinzi 12:9", "it": "La mia grazia ti basta, perché la mia potenza si dimostra perfetta nella debolezza.", "en": "My grace is sufficient for you, for my power is made perfect in weakness.", "es": "Bástate mi gracia; porque mi poder se perfecciona en la debilidad."},
    {"reference": "Efesini 3:20", "it": "A colui che può fare infinitamente di più di quel che domandiamo o pensiamo.", "en": "To him who is able to do far more abundantly than all that we ask or think.", "es": "A Aquel que es poderoso para hacer todas las cosas mucho más abundantemente."},
    {"reference": "Salmi 32:8", "it": "Io ti istruirò e ti insegnerò la via per la quale devi camminare.", "en": "I will instruct you and teach you in the way you should go.", "es": "Te haré entender, y te enseñaré el camino en que debes andar."},
    {"reference": "Giovanni 10:10", "it": "Io sono venuto perché abbiano la vita e l'abbiano in abbondanza.", "en": "I came that they may have life and have it abundantly.", "es": "Yo he venido para que tengan vida, y para que la tengan en abundancia."},
    {"reference": "Proverbi 4:23", "it": "Custodisci il tuo cuore più di ogni altra cosa, perché da esso proviene la vita.", "en": "Keep your heart with all vigilance, for from it flow the springs of life.", "es": "Sobre toda cosa guardada, guarda tu corazón; porque de él mana la vida."},
    {"reference": "1 Corinzi 13:4-5", "it": "L'amore è paziente, è benevolo; l'amore non invidia.", "en": "Love is patient and kind; love does not envy.", "es": "El amor es sufrido, es benigno; el amor no tiene envidia."},
    # Marzo (60-90)
    {"reference": "Salmi 19:1", "it": "I cieli raccontano la gloria di Dio.", "en": "The heavens declare the glory of God.", "es": "Los cielos cuentan la gloria de Dios."},
    {"reference": "Giovanni 1:12", "it": "A tutti quelli che l'hanno ricevuto ha dato il diritto di diventare figli di Dio.", "en": "To all who received him, he gave the right to become children of God.", "es": "A todos los que le recibieron, les dio potestad de ser hechos hijos de Dios."},
    {"reference": "Romani 6:23", "it": "Il dono di Dio è la vita eterna in Cristo Gesù, nostro Signore.", "en": "The free gift of God is eternal life in Christ Jesus our Lord.", "es": "La dádiva de Dios es vida eterna en Cristo Jesús Señor nuestro."},
    {"reference": "Salmi 40:1-2", "it": "Ho pazientemente aspettato il SIGNORE, ed egli si è chinato su di me.", "en": "I waited patiently for the LORD; he inclined to me.", "es": "Pacientemente esperé a Jehová, y se inclinó a mí."},
    {"reference": "Matteo 22:37-39", "it": "Ama il Signore Dio tuo con tutto il tuo cuore.", "en": "Love the Lord your God with all your heart.", "es": "Amarás al Señor tu Dios con todo tu corazón."},
    {"reference": "Isaia 43:2", "it": "Quando passerai attraverso le acque, io sarò con te.", "en": "When you pass through the waters, I will be with you.", "es": "Cuando pases por las aguas, yo estaré contigo."},
    {"reference": "Salmi 84:11", "it": "Il SIGNORE Dio è sole e scudo; il SIGNORE concede grazia e gloria.", "en": "The LORD God is a sun and shield; the LORD bestows favor and honor.", "es": "Sol y escudo es Jehová Dios; gracia y gloria dará Jehová."},
    {"reference": "Giovanni 14:27", "it": "Vi lascio pace; vi do la mia pace.", "en": "Peace I leave with you; my peace I give to you.", "es": "La paz os dejo, mi paz os doy."},
    {"reference": "Filippesi 4:6-7", "it": "Non angustiatevi di nulla, ma in ogni cosa fate conoscere le vostre richieste a Dio.", "en": "Do not be anxious about anything, but in everything by prayer present your requests to God.", "es": "Por nada estéis afanosos, sino sean conocidas vuestras peticiones delante de Dios."},
    {"reference": "Salmi 73:26", "it": "La mia carne e il mio cuore possono venir meno, ma Dio è la rocca del mio cuore.", "en": "My flesh and my heart may fail, but God is the strength of my heart.", "es": "Mi carne y mi corazón desfallecen; mas la roca de mi corazón y mi porción es Dios."},
    {"reference": "Proverbi 3:9-10", "it": "Onora il SIGNORE con i tuoi beni e con le primizie di ogni tuo raccolto.", "en": "Honor the LORD with your wealth and with the firstfruits of all your produce.", "es": "Honra a Jehová con tus bienes, y con las primicias de todos tus frutos."},
    {"reference": "Matteo 5:6", "it": "Beati quelli che sono affamati e assetati di giustizia, perché saranno saziati.", "en": "Blessed are those who hunger and thirst for righteousness, for they shall be satisfied.", "es": "Bienaventurados los que tienen hambre y sed de justicia, porque ellos serán saciados."},
    {"reference": "Salmi 107:1", "it": "Celebrate il SIGNORE, perché egli è buono, perché la sua bontà dura in eterno.", "en": "Oh give thanks to the LORD, for he is good, for his steadfast love endures forever!", "es": "Alabad a Jehová, porque él es bueno; porque para siempre es su misericordia."},
    {"reference": "Giovanni 11:25-26", "it": "Io sono la risurrezione e la vita; chi crede in me, anche se muore, vivrà.", "en": "I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live.", "es": "Yo soy la resurrección y la vida; el que cree en mí, aunque esté muerto, vivirá."},
    {"reference": "Romani 8:31", "it": "Se Dio è per noi, chi sarà contro di noi?", "en": "If God is for us, who can be against us?", "es": "Si Dios es por nosotros, ¿quién contra nosotros?"},
    {"reference": "Salmi 23:4", "it": "Quand'anche camminassi nella valle dell'ombra della morte, non temerei alcun male.", "en": "Even though I walk through the valley of the shadow of death, I will fear no evil.", "es": "Aunque ande en valle de sombra de muerte, no temeré mal alguno."},
    {"reference": "1 Corinzi 15:58", "it": "Siate saldi, incrollabili, sempre abbondanti nell'opera del Signore.", "en": "Be steadfast, immovable, always abounding in the work of the Lord.", "es": "Estad firmes y constantes, creciendo en la obra del Señor siempre."},
    {"reference": "Isaia 55:8-9", "it": "I miei pensieri non sono i vostri pensieri, né le vostre vie sono le mie vie.", "en": "My thoughts are not your thoughts, neither are your ways my ways.", "es": "Mis pensamientos no son vuestros pensamientos, ni vuestros caminos mis caminos."},
    {"reference": "Salmi 86:5", "it": "Tu, o Signore, sei buono e pronto a perdonare.", "en": "For you, O Lord, are good and forgiving.", "es": "Porque tú, Señor, eres bueno y perdonador."},
    {"reference": "Giovanni 13:34-35", "it": "Vi do un nuovo comandamento: che vi amiate gli uni gli altri.", "en": "A new commandment I give to you, that you love one another.", "es": "Un mandamiento nuevo os doy: Que os améis unos a otros."},
    {"reference": "Proverbi 22:6", "it": "Insegna al ragazzo la condotta che deve tenere.", "en": "Train up a child in the way he should go.", "es": "Instruye al niño en su camino."},
    {"reference": "Salmi 42:1-2", "it": "Come la cerva desidera i corsi d'acqua, così l'anima mia anela a te, o Dio.", "en": "As a deer pants for flowing streams, so pants my soul for you, O God.", "es": "Como el ciervo brama por las corrientes de las aguas, así clama por ti, oh Dios, el alma mía."},
    {"reference": "Matteo 6:9-13", "it": "Padre nostro che sei nei cieli, sia santificato il tuo nome.", "en": "Our Father in heaven, hallowed be your name.", "es": "Padre nuestro que estás en los cielos, santificado sea tu nombre."},
    {"reference": "Romani 10:9", "it": "Se confessi con la tua bocca che Gesù è il Signore e credi nel tuo cuore, sarai salvato.", "en": "If you confess with your mouth that Jesus is Lord and believe in your heart, you will be saved.", "es": "Si confesares con tu boca que Jesús es el Señor, y creyeres en tu corazón, serás salvo."},
    {"reference": "Salmi 147:3", "it": "Egli guarisce chi ha il cuore spezzato e fascia le loro ferite.", "en": "He heals the brokenhearted and binds up their wounds.", "es": "El sana a los quebrantados de corazón, y venda sus heridas."},
    {"reference": "Giovanni 15:13", "it": "Nessuno ha amore più grande di questo: dare la sua vita per i suoi amici.", "en": "Greater love has no one than this, that someone lay down his life for his friends.", "es": "Nadie tiene mayor amor que este, que uno ponga su vida por sus amigos."},
    {"reference": "1 Pietro 2:9", "it": "Voi siete una stirpe eletta, un sacerdozio regale.", "en": "You are a chosen race, a royal priesthood.", "es": "Vosotros sois linaje escogido, real sacerdocio."},
    {"reference": "Salmi 138:8", "it": "Il SIGNORE compirà in mio favore l'opera sua.", "en": "The LORD will fulfill his purpose for me.", "es": "Jehová cumplirá su propósito en mí."},
    {"reference": "Efesini 6:10", "it": "Del resto, fortificatevi nel Signore e nella forza della sua potenza.", "en": "Be strong in the Lord and in the strength of his might.", "es": "Fortaleceos en el Señor, y en el poder de su fuerza."},
    {"reference": "Proverbi 12:25", "it": "L'ansia nel cuore dell'uomo lo abbatte, ma una buona parola lo rallegra.", "en": "Anxiety in a man's heart weighs him down, but a good word makes him glad.", "es": "La congoja en el corazón del hombre lo abate; mas la buena palabra lo alegra."},
    {"reference": "Salmi 30:5", "it": "Il pianto può durare una notte, ma la mattina viene la gioia.", "en": "Weeping may tarry for the night, but joy comes with the morning.", "es": "Por la noche durará el lloro, y a la mañana vendrá la alegría."},
    # Aprile (91-120)
    {"reference": "Giovanni 6:35", "it": "Io sono il pane della vita; chi viene a me non avrà fame.", "en": "I am the bread of life; whoever comes to me shall not hunger.", "es": "Yo soy el pan de vida; el que a mí viene, nunca tendrá hambre."},
    {"reference": "Romani 12:12", "it": "Siate gioiosi nella speranza, pazienti nella tribolazione, perseveranti nella preghiera.", "en": "Rejoice in hope, be patient in tribulation, be constant in prayer.", "es": "Gozosos en la esperanza; sufridos en la tribulación; constantes en la oración."},
    {"reference": "Salmi 16:11", "it": "Tu mi farai conoscere il sentiero della vita.", "en": "You make known to me the path of life.", "es": "Me mostrarás la senda de la vida."},
    {"reference": "Matteo 5:9", "it": "Beati quelli che si adoperano per la pace, perché saranno chiamati figli di Dio.", "en": "Blessed are the peacemakers, for they shall be called sons of God.", "es": "Bienaventurados los pacificadores, porque ellos serán llamados hijos de Dios."},
    {"reference": "Isaia 12:2", "it": "Dio è la mia salvezza; io avrò fiducia, e non temerò.", "en": "God is my salvation; I will trust, and will not be afraid.", "es": "Dios es salvación mía; me aseguraré y no temeré."},
    {"reference": "Salmi 63:1", "it": "O Dio, tu sei il mio Dio, io ti cerco dall'alba.", "en": "O God, you are my God; earnestly I seek you.", "es": "Dios, Dios mío eres tú; de madrugada te buscaré."},
    {"reference": "Giovanni 4:14", "it": "Chi beve dell'acqua che io gli darò, non avrà mai più sete.", "en": "Whoever drinks of the water that I will give him will never be thirsty again.", "es": "El que bebiere del agua que yo le daré, no tendrá sed jamás."},
    {"reference": "Filippesi 1:6", "it": "Colui che ha cominciato in voi un'opera buona, la condurrà a compimento.", "en": "He who began a good work in you will bring it to completion.", "es": "El que comenzó en vosotros la buena obra, la perfeccionará."},
    {"reference": "Salmi 90:12", "it": "Insegnaci dunque a contare bene i nostri giorni.", "en": "Teach us to number our days.", "es": "Enséñanos de tal modo a contar nuestros días."},
    {"reference": "Proverbi 15:1", "it": "La risposta dolce calma il furore, ma la parola dura eccita l'ira.", "en": "A soft answer turns away wrath, but a harsh word stirs up anger.", "es": "La blanda respuesta quita la ira; mas la palabra áspera hace subir el furor."},
    {"reference": "Matteo 18:20", "it": "Dove due o tre sono riuniti nel mio nome, lì sono io in mezzo a loro.", "en": "Where two or three are gathered in my name, there am I among them.", "es": "Donde están dos o tres congregados en mi nombre, allí estoy yo en medio de ellos."},
    {"reference": "Romani 8:38-39", "it": "Niente potrà separarci dall'amore di Dio che è in Cristo Gesù.", "en": "Nothing will be able to separate us from the love of God in Christ Jesus.", "es": "Nada nos podrá separar del amor de Dios, que es en Cristo Jesús."},
    {"reference": "Salmi 143:8", "it": "Fammi sentire al mattino la tua grazia, perché in te confido.", "en": "Let me hear in the morning of your steadfast love, for in you I trust.", "es": "Hazme oír por la mañana tu misericordia, porque en ti he confiado."},
    {"reference": "Giovanni 8:12", "it": "Io sono la luce del mondo; chi mi segue non camminerà nelle tenebre.", "en": "I am the light of the world. Whoever follows me will not walk in darkness.", "es": "Yo soy la luz del mundo; el que me sigue, no andará en tinieblas."},
    {"reference": "1 Corinzi 2:9", "it": "Le cose che occhio non vide, che orecchio non udì, Dio le ha preparate per quelli che lo amano.", "en": "What no eye has seen, nor ear heard, God has prepared for those who love him.", "es": "Cosas que ojo no vio, ni oído oyó, son las que Dios ha preparado para los que le aman."},
    {"reference": "Salmi 46:10", "it": "Fermatevi e riconoscete che io sono Dio.", "en": "Be still, and know that I am God.", "es": "Estad quietos, y conoced que yo soy Dios."},
    {"reference": "Proverbi 11:25", "it": "Chi è generoso sarà nell'abbondanza.", "en": "Whoever brings blessing will be enriched.", "es": "El alma generosa será satisfecha."},
    {"reference": "Matteo 11:29", "it": "Prendete su di voi il mio giogo e imparate da me.", "en": "Take my yoke upon you, and learn from me.", "es": "Llevad mi yugo sobre vosotros, y aprended de mí."},
    {"reference": "Isaia 53:5", "it": "Per le sue lividure noi siamo stati guariti.", "en": "With his wounds we are healed.", "es": "Por su llaga fuimos nosotros curados."},
    {"reference": "Salmi 95:1-2", "it": "Venite, cantiamo con gioia al SIGNORE.", "en": "Come, let us sing for joy to the LORD.", "es": "Venid, aclamemos alegremente a Jehová."},
    {"reference": "Giovanni 17:17", "it": "Santificali nella verità; la tua parola è verità.", "en": "Sanctify them in the truth; your word is truth.", "es": "Santifícalos en tu verdad; tu palabra es verdad."},
    {"reference": "Romani 1:16", "it": "Il vangelo è potenza di Dio per la salvezza di chiunque crede.", "en": "The gospel is the power of God for salvation to everyone who believes.", "es": "El evangelio es poder de Dios para salvación a todo aquel que cree."},
    {"reference": "Salmi 103:11-12", "it": "Come i cieli sono alti al di sopra della terra, così è grande la sua bontà.", "en": "As high as the heavens are above the earth, so great is his steadfast love.", "es": "Como la altura de los cielos sobre la tierra, engrandeció su misericordia."},
    {"reference": "Proverbi 31:25", "it": "Forza e dignità sono il suo vestito, ed essa ride dell'avvenire.", "en": "Strength and dignity are her clothing, and she laughs at the time to come.", "es": "Fuerza y honor son su vestidura; y se ríe de lo por venir."},
    {"reference": "Matteo 7:12", "it": "Tutte le cose che voi volete che gli uomini vi facciano, fatele anche voi a loro.", "en": "Whatever you wish that others would do to you, do also to them.", "es": "Todas las cosas que queráis que los hombres hagan con vosotros, así también haced vosotros con ellos."},
    {"reference": "1 Giovanni 3:1", "it": "Vedete quale amore ci ha manifestato il Padre.", "en": "See what kind of love the Father has given to us.", "es": "Mirad cuál amor nos ha dado el Padre."},
    {"reference": "Salmi 77:14", "it": "Tu sei il Dio che fa meraviglie.", "en": "You are the God who works wonders.", "es": "Tú eres el Dios que hace maravillas."},
    {"reference": "Giovanni 20:29", "it": "Beati quelli che non hanno visto e hanno creduto.", "en": "Blessed are those who have not seen and yet have believed.", "es": "Bienaventurados los que no vieron, y creyeron."},
    {"reference": "Efesini 4:32", "it": "Siate benevoli e compassionevoli gli uni verso gli altri.", "en": "Be kind to one another, tenderhearted, forgiving one another.", "es": "Sed benignos unos con otros, misericordiosos, perdonándoos unos a otros."},
    {"reference": "Salmi 150:6", "it": "Ogni cosa che respira lodi il SIGNORE. Alleluia!", "en": "Let everything that has breath praise the LORD! Praise the LORD!", "es": "Todo lo que respira alabe a JAH. Aleluya."},
    # Maggio (121-151)
    {"reference": "Giovanni 5:24", "it": "Chi ascolta la mia parola e crede, ha vita eterna.", "en": "Whoever hears my word and believes has eternal life.", "es": "El que oye mi palabra, y cree, tiene vida eterna."},
    {"reference": "Romani 3:23-24", "it": "Tutti hanno peccato e sono giustificati gratuitamente per la sua grazia.", "en": "All have sinned and are justified by his grace as a gift.", "es": "Todos pecaron, y son justificados gratuitamente por su gracia."},
    {"reference": "Salmi 18:2", "it": "Il SIGNORE è la mia rocca, la mia fortezza, il mio liberatore.", "en": "The LORD is my rock and my fortress and my deliverer.", "es": "Jehová, roca mía y castillo mío, y mi libertador."},
    {"reference": "Matteo 16:26", "it": "Che gioverà a un uomo se guadagna tutto il mondo e perde l'anima sua?", "en": "What will it profit a man if he gains the whole world and forfeits his soul?", "es": "¿Qué aprovechará al hombre, si ganare todo el mundo, y perdiere su alma?"},
    {"reference": "Isaia 40:29", "it": "Egli dà forza allo stanco e accresce il vigore a colui che è spossato.", "en": "He gives power to the faint, and to him who has no might he increases strength.", "es": "Él da esfuerzo al cansado, y multiplica las fuerzas al que no tiene ningunas."},
    {"reference": "Salmi 56:3", "it": "Nel giorno della paura, io confido in te.", "en": "When I am afraid, I put my trust in you.", "es": "En el día que temo, yo en ti confío."},
    {"reference": "Giovanni 14:1", "it": "Il vostro cuore non sia turbato; credete in Dio, e credete anche in me.", "en": "Let not your hearts be troubled. Believe in God; believe also in me.", "es": "No se turbe vuestro corazón; creéis en Dios, creed también en mí."},
    {"reference": "Filippesi 2:13", "it": "Dio è colui che produce in voi il volere e l'operare.", "en": "It is God who works in you, both to will and to work.", "es": "Dios es el que en vosotros produce así el querer como el hacer."},
    {"reference": "Salmi 37:5", "it": "Rimetti la tua sorte nel SIGNORE; confida in lui, ed egli opererà.", "en": "Commit your way to the LORD; trust in him, and he will act.", "es": "Encomienda a Jehová tu camino, y confía en él; y él hará."},
    {"reference": "Proverbi 19:21", "it": "Ci sono molti disegni nel cuore dell'uomo, ma il piano del SIGNORE è quello che sussiste.", "en": "Many are the plans in the mind of a man, but it is the purpose of the LORD that will stand.", "es": "Muchos pensamientos hay en el corazón del hombre; mas el consejo de Jehová permanecerá."},
    {"reference": "Matteo 5:3", "it": "Beati i poveri in spirito, perché di loro è il regno dei cieli.", "en": "Blessed are the poor in spirit, for theirs is the kingdom of heaven.", "es": "Bienaventurados los pobres en espíritu, porque de ellos es el reino de los cielos."},
    {"reference": "Romani 14:8", "it": "Se viviamo, viviamo per il Signore; e se moriamo, moriamo per il Signore.", "en": "If we live, we live to the Lord, and if we die, we die to the Lord.", "es": "Si vivimos, para el Señor vivimos; y si morimos, para el Señor morimos."},
    {"reference": "Salmi 25:4-5", "it": "Fammi conoscere le tue vie, o SIGNORE; insegnami i tuoi sentieri.", "en": "Make me to know your ways, O LORD; teach me your paths.", "es": "Muéstrame, oh Jehová, tus caminos; enséñame tus sendas."},
    {"reference": "Giovanni 14:2-3", "it": "Nella casa del Padre mio ci sono molte dimore; vado a prepararvi un luogo.", "en": "In my Father's house are many rooms. I go to prepare a place for you.", "es": "En la casa de mi Padre muchas moradas hay; voy a preparar lugar para vosotros."},
    {"reference": "1 Corinzi 16:13", "it": "Vegliate, state fermi nella fede, comportatevi virilmente, fortificatevi.", "en": "Be watchful, stand firm in the faith, act like men, be strong.", "es": "Velad, estad firmes en la fe; portaos varonilmente, y esforzaos."},
    {"reference": "Salmi 34:4", "it": "Ho cercato il SIGNORE, ed egli m'ha risposto; m'ha liberato da tutti i miei spaventi.", "en": "I sought the LORD, and he answered me and delivered me from all my fears.", "es": "Busqué a Jehová, y él me oyó, y me libró de todos mis temores."},
    {"reference": "Proverbi 27:17", "it": "Il ferro affila il ferro; così un uomo ne affila un altro.", "en": "Iron sharpens iron, and one man sharpens another.", "es": "Hierro con hierro se aguza; y así el hombre aguza el rostro de su amigo."},
    {"reference": "Matteo 6:25", "it": "Non siate dunque in ansia per la vostra vita.", "en": "Do not be anxious about your life.", "es": "No os afanéis por vuestra vida."},
    {"reference": "Isaia 58:11", "it": "Il SIGNORE ti guiderà sempre.", "en": "The LORD will guide you continually.", "es": "Jehová te pastoreará siempre."},
    {"reference": "Salmi 92:1-2", "it": "È bello celebrare il SIGNORE e cantare le tue lodi, o Altissimo.", "en": "It is good to give thanks to the LORD, to sing praises to your name, O Most High.", "es": "Bueno es alabarte, oh Jehová, y cantar salmos a tu nombre, oh Altísimo."},
    {"reference": "Giovanni 15:9", "it": "Come il Padre mi ha amato, così anch'io ho amato voi; dimorate nel mio amore.", "en": "As the Father has loved me, so have I loved you. Abide in my love.", "es": "Como el Padre me ha amado, así también yo os he amado; permaneced en mi amor."},
    {"reference": "Romani 8:1", "it": "Non c'è dunque più nessuna condanna per quelli che sono in Cristo Gesù.", "en": "There is therefore now no condemnation for those who are in Christ Jesus.", "es": "Ninguna condenación hay para los que están en Cristo Jesús."},
    {"reference": "Salmi 4:8", "it": "In pace mi coricherò e in pace dormirò, perché tu solo, o SIGNORE, mi fai abitare al sicuro.", "en": "In peace I will both lie down and sleep; for you alone, O LORD, make me dwell in safety.", "es": "En paz me acostaré, y asimismo dormiré; porque solo tú, Jehová, me haces vivir confiado."},
    {"reference": "Proverbi 16:9", "it": "Il cuore dell'uomo medita la sua via, ma il SIGNORE dirige i suoi passi.", "en": "The heart of man plans his way, but the LORD establishes his steps.", "es": "El corazón del hombre piensa su camino; mas Jehová endereza sus pasos."},
    {"reference": "Matteo 5:44", "it": "Amate i vostri nemici e pregate per quelli che vi perseguitano.", "en": "Love your enemies and pray for those who persecute you.", "es": "Amad a vuestros enemigos, y orad por los que os persiguen."},
    {"reference": "1 Giovanni 5:14", "it": "Se domandiamo qualche cosa secondo la sua volontà, egli ci esaudisce.", "en": "If we ask anything according to his will he hears us.", "es": "Si pedimos alguna cosa conforme a su voluntad, él nos oye."},
    {"reference": "Salmi 57:10", "it": "Grande fino ai cieli è la tua bontà.", "en": "Great is your steadfast love to the heavens.", "es": "Grande es hasta los cielos tu misericordia."},
    {"reference": "Giovanni 12:46", "it": "Io sono venuto come luce nel mondo.", "en": "I have come into the world as light.", "es": "Yo, la luz, he venido al mundo."},
    {"reference": "Efesini 2:10", "it": "Siamo opera sua, creati in Cristo Gesù per le buone opere.", "en": "We are his workmanship, created in Christ Jesus for good works.", "es": "Somos hechura suya, creados en Cristo Jesús para buenas obras."},
    {"reference": "Salmi 116:1-2", "it": "Io amo il SIGNORE perché ha udito la mia voce e le mie suppliche.", "en": "I love the LORD, because he has heard my voice and my pleas for mercy.", "es": "Amo a Jehová, pues ha oído mi voz y mis súplicas."},
    {"reference": "Proverbi 3:7-8", "it": "Non ti stimare saggio da te stesso; temi il SIGNORE e allontanati dal male.", "en": "Be not wise in your own eyes; fear the LORD, and turn away from evil.", "es": "No seas sabio en tu propia opinión; teme a Jehová, y apártate del mal."},
    # Giugno (152-181)
    {"reference": "Giovanni 3:30", "it": "Bisogna che egli cresca, e che io diminuisca.", "en": "He must increase, but I must decrease.", "es": "Es necesario que él crezca, pero que yo mengüe."},
    {"reference": "Romani 15:4", "it": "Le Scritture ci sono state scritte per nostra istruzione.", "en": "Whatever was written was written for our instruction.", "es": "Las cosas que se escribieron antes, para nuestra enseñanza se escribieron."},
    {"reference": "Salmi 31:24", "it": "Siate forti, il vostro cuore si rinfranchi, o voi tutti che sperate nel SIGNORE.", "en": "Be strong, and let your heart take courage, all you who wait for the LORD!", "es": "Esforzaos todos vosotros los que esperáis en Jehová, y tome aliento vuestro corazón."},
    {"reference": "Matteo 19:26", "it": "Ogni cosa è possibile a Dio.", "en": "With God all things are possible.", "es": "Para Dios todo es posible."},
    {"reference": "Isaia 30:15", "it": "Nel tornare a me e nello stare tranquilli starà la vostra salvezza.", "en": "In returning and rest you shall be saved.", "es": "En descanso y en reposo seréis salvos."},
    {"reference": "Salmi 5:3", "it": "Al mattino tu ascolti la mia voce.", "en": "In the morning, O LORD, you hear my voice.", "es": "Oh Jehová, de mañana oirás mi voz."},
    {"reference": "Giovanni 10:27-28", "it": "Le mie pecore ascoltano la mia voce e io le conosco, ed esse mi seguono.", "en": "My sheep hear my voice, and I know them, and they follow me.", "es": "Mis ovejas oyen mi voz, y yo las conozco, y me siguen."},
    {"reference": "Filippesi 3:13-14", "it": "Dimentico le cose che stanno dietro e mi protendo verso quelle che stanno davanti.", "en": "Forgetting what lies behind and straining forward to what lies ahead.", "es": "Olvidando ciertamente lo que queda atrás, y extendiéndome a lo que está delante."},
    {"reference": "Salmi 66:20", "it": "Benedetto sia Dio, che non ha respinto la mia preghiera.", "en": "Blessed be God, because he has not rejected my prayer.", "es": "Bendito sea Dios, que no echó de sí mi oración."},
    {"reference": "Proverbi 14:26", "it": "Nel timore del SIGNORE c'è una grande sicurezza.", "en": "In the fear of the LORD one has strong confidence.", "es": "En el temor de Jehová está la fuerte confianza."},
    {"reference": "Matteo 9:13", "it": "Non sono venuto a chiamare dei giusti, ma dei peccatori.", "en": "I came not to call the righteous, but sinners.", "es": "No he venido a llamar a justos, sino a pecadores."},
    {"reference": "Romani 6:14", "it": "Il peccato non avrà più dominio su di voi.", "en": "Sin will have no dominion over you.", "es": "El pecado no se enseñoreará de vosotros."},
    {"reference": "Salmi 145:9", "it": "Il SIGNORE è buono verso tutti, pieno di compassione per tutte le sue opere.", "en": "The LORD is good to all, and his mercy is over all that he has made.", "es": "Bueno es Jehová para con todos, y sus misericordias sobre todas sus obras."},
    {"reference": "Giovanni 7:37-38", "it": "Se qualcuno ha sete, venga a me e beva.", "en": "If anyone thirsts, let him come to me and drink.", "es": "Si alguno tiene sed, venga a mí y beba."},
    {"reference": "1 Corinzi 6:19-20", "it": "Il vostro corpo è il tempio dello Spirito Santo.", "en": "Your body is a temple of the Holy Spirit.", "es": "Vuestro cuerpo es templo del Espíritu Santo."},
    {"reference": "Salmi 8:1", "it": "O SIGNORE, Signore nostro, quant'è magnifico il tuo nome in tutta la terra!", "en": "O LORD, our Lord, how majestic is your name in all the earth!", "es": "¡Oh Jehová, Señor nuestro, cuán glorioso es tu nombre en toda la tierra!"},
    {"reference": "Proverbi 10:22", "it": "La benedizione del SIGNORE è quella che arricchisce.", "en": "The blessing of the LORD makes rich.", "es": "La bendición de Jehová es la que enriquece."},
    {"reference": "Matteo 4:19", "it": "Venite dietro a me e vi farò pescatori di uomini.", "en": "Follow me, and I will make you fishers of men.", "es": "Venid en pos de mí, y os haré pescadores de hombres."},
    {"reference": "Isaia 54:10", "it": "La mia benevolenza non si allontanerà da te.", "en": "My steadfast love shall not depart from you.", "es": "Mi misericordia no se apartará de ti."},
    {"reference": "Salmi 71:5", "it": "Tu sei la mia speranza, o Signore, Dio.", "en": "For you, O Lord, are my hope.", "es": "Porque tú, oh Señor Jehová, eres mi esperanza."},
    {"reference": "Giovanni 1:14", "it": "La Parola è diventata carne e ha abitato per un tempo fra di noi.", "en": "The Word became flesh and dwelt among us.", "es": "Aquel Verbo fue hecho carne, y habitó entre nosotros."},
    {"reference": "Romani 4:20-21", "it": "Davanti alla promessa di Dio non vacillò per incredulità.", "en": "He did not waver concerning the promise of God.", "es": "No dudó, por incredulidad, de la promesa de Dios."},
    {"reference": "Salmi 33:4", "it": "La parola del SIGNORE è retta e tutta l'opera sua è fatta con fedeltà.", "en": "For the word of the LORD is upright, and all his work is done in faithfulness.", "es": "Porque recta es la palabra de Jehová, y toda su obra es hecha con fidelidad."},
    {"reference": "Proverbi 17:17", "it": "L'amico ama in ogni tempo.", "en": "A friend loves at all times.", "es": "En todo tiempo ama el amigo."},
    {"reference": "Matteo 25:40", "it": "In verità vi dico: tutte le volte che l'avete fatto a uno di questi minimi fratelli, l'avete fatto a me.", "en": "As you did it to one of the least of these my brothers, you did it to me.", "es": "En cuanto lo hicisteis a uno de estos mis hermanos más pequeños, a mí lo hicisteis."},
    {"reference": "1 Giovanni 4:4", "it": "Colui che è in voi è più grande di colui che è nel mondo.", "en": "He who is in you is greater than he who is in the world.", "es": "Mayor es el que está en vosotros, que el que está en el mundo."},
    {"reference": "Salmi 91:11", "it": "Egli darà ordine ai suoi angeli di proteggerti in tutte le tue vie.", "en": "He will command his angels concerning you to guard you in all your ways.", "es": "Pues a sus ángeles mandará acerca de ti, que te guarden en todos tus caminos."},
    {"reference": "Giovanni 16:24", "it": "Chiedete e riceverete, affinché la vostra gioia sia completa.", "en": "Ask, and you will receive, that your joy may be full.", "es": "Pedid, y recibiréis, para que vuestro gozo sea cumplido."},
    {"reference": "Efesini 1:7", "it": "In lui abbiamo la redenzione mediante il suo sangue.", "en": "In him we have redemption through his blood.", "es": "En quien tenemos redención por su sangre."},
    {"reference": "Salmi 68:19", "it": "Benedetto sia il Signore! Ogni giorno egli porta i nostri pesi.", "en": "Blessed be the Lord, who daily bears us up.", "es": "Bendito el Señor; cada día nos colma de beneficios."},
    # Luglio (182-212)
    {"reference": "Giovanni 6:68", "it": "Signore, da chi andremmo noi? Tu hai parole di vita eterna.", "en": "Lord, to whom shall we go? You have the words of eternal life.", "es": "Señor, ¿a quién iremos? Tú tienes palabras de vida eterna."},
    {"reference": "Romani 8:18", "it": "Le sofferenze del tempo presente non sono paragonabili alla gloria che sarà rivelata.", "en": "The sufferings of this present time are not worth comparing with the glory to be revealed.", "es": "Las aflicciones del tiempo presente no son comparables con la gloria venidera."},
    {"reference": "Salmi 136:1", "it": "Celebrate il SIGNORE, perché egli è buono; perché la sua bontà dura in eterno.", "en": "Give thanks to the LORD, for he is good, for his steadfast love endures forever.", "es": "Alabad a Jehová, porque él es bueno, porque para siempre es su misericordia."},
    {"reference": "Matteo 5:8", "it": "Beati i puri di cuore, perché vedranno Dio.", "en": "Blessed are the pure in heart, for they shall see God.", "es": "Bienaventurados los de limpio corazón, porque ellos verán a Dios."},
    {"reference": "Isaia 49:15-16", "it": "Può una donna dimenticare il bimbo che allatta? Io non ti dimenticherò.", "en": "Can a woman forget her nursing child? I will not forget you.", "es": "¿Se olvidará la mujer de lo que dio a luz? Yo nunca me olvidaré de ti."},
    {"reference": "Salmi 23:6", "it": "Certo, beni e bontà m'accompagneranno tutti i giorni della mia vita.", "en": "Surely goodness and mercy shall follow me all the days of my life.", "es": "Ciertamente el bien y la misericordia me seguirán todos los días de mi vida."},
    {"reference": "Giovanni 21:15", "it": "Mi ami tu? Pasci i miei agnelli.", "en": "Do you love me? Feed my lambs.", "es": "¿Me amas? Apacienta mis corderos."},
    {"reference": "Filippesi 4:8", "it": "Tutte le cose vere, tutte le cose onorevoli... siano oggetto dei vostri pensieri.", "en": "Whatever is true, whatever is honorable... think about these things.", "es": "Todo lo que es verdadero, todo lo honesto... en esto pensad."},
    {"reference": "Salmi 119:11", "it": "Ho conservato la tua parola nel mio cuore per non peccare contro di te.", "en": "I have stored up your word in my heart, that I might not sin against you.", "es": "En mi corazón he guardado tus dichos, para no pecar contra ti."},
    {"reference": "Proverbi 16:24", "it": "Le parole gentili sono un favo di miele; dolcezza per l'anima e salute per le ossa.", "en": "Gracious words are like a honeycomb, sweetness to the soul and health to the body.", "es": "Panal de miel son los dichos suaves; suavidad al alma y medicina para los huesos."},
    {"reference": "Matteo 10:31", "it": "Non temete dunque; voi valete più di molti passeri.", "en": "Fear not, therefore; you are of more value than many sparrows.", "es": "Así que, no temáis; más valéis vosotros que muchos pajarillos."},
    {"reference": "Romani 5:1", "it": "Giustificati per fede, abbiamo pace con Dio per mezzo di Gesù Cristo.", "en": "Justified by faith, we have peace with God through our Lord Jesus Christ.", "es": "Justificados por la fe, tenemos paz para con Dios por medio de nuestro Señor Jesucristo."},
    {"reference": "Salmi 9:1-2", "it": "Io celebrerò il SIGNORE con tutto il mio cuore.", "en": "I will give thanks to the LORD with my whole heart.", "es": "Te alabaré, oh Jehová, con todo mi corazón."},
    {"reference": "Giovanni 8:36", "it": "Se dunque il Figlio vi farà liberi, sarete veramente liberi.", "en": "If the Son sets you free, you will be free indeed.", "es": "Si el Hijo os libertare, seréis verdaderamente libres."},
    {"reference": "1 Corinzi 13:13", "it": "Ora rimangono queste tre cose: fede, speranza e amore; ma la più grande di esse è l'amore.", "en": "Now these three remain: faith, hope and love. But the greatest of these is love.", "es": "Ahora permanecen la fe, la esperanza y el amor, estos tres; pero el mayor de ellos es el amor."},
    {"reference": "Salmi 126:5", "it": "Quelli che seminano con lacrime, mieteranno con canti di gioia.", "en": "Those who sow in tears shall reap with shouts of joy.", "es": "Los que sembraron con lágrimas, con regocijo segarán."},
    {"reference": "Proverbi 3:11-12", "it": "Figlio mio, non disprezzare la correzione del SIGNORE.", "en": "My son, do not despise the LORD's discipline.", "es": "No menosprecies, hijo mío, el castigo de Jehová."},
    {"reference": "Matteo 6:6", "it": "Quando preghi, entra nella tua cameretta, chiudi la porta e prega il Padre tuo.", "en": "When you pray, go into your room and shut the door and pray to your Father.", "es": "Cuando ores, entra en tu aposento, y cerrada la puerta, ora a tu Padre."},
    {"reference": "Isaia 61:1", "it": "Lo Spirito del Signore è su di me, perché mi ha unto per portare il lieto messaggio.", "en": "The Spirit of the Lord GOD is upon me, because the LORD has anointed me to bring good news.", "es": "El Espíritu de Jehová el Señor está sobre mí, porque me ungió para predicar buenas nuevas."},
    {"reference": "Salmi 113:3", "it": "Dal sol levante fino al ponente sia lodato il nome del SIGNORE.", "en": "From the rising of the sun to its setting, the name of the LORD is to be praised.", "es": "Desde el nacimiento del sol hasta donde se pone, sea alabado el nombre de Jehová."},
    {"reference": "Giovanni 6:63", "it": "Le parole che vi ho dette sono spirito e vita.", "en": "The words that I have spoken to you are spirit and life.", "es": "Las palabras que yo os he hablado son espíritu y son vida."},
    {"reference": "Romani 12:1", "it": "Vi esorto a presentare i vostri corpi in sacrificio vivente, santo, gradito a Dio.", "en": "Present your bodies as a living sacrifice, holy and acceptable to God.", "es": "Presentéis vuestros cuerpos en sacrificio vivo, santo, agradable a Dios."},
    {"reference": "Salmi 111:10", "it": "Il timore del SIGNORE è il principio della sapienza.", "en": "The fear of the LORD is the beginning of wisdom.", "es": "El principio de la sabiduría es el temor de Jehová."},
    {"reference": "Proverbi 18:21", "it": "Morte e vita sono in potere della lingua.", "en": "Death and life are in the power of the tongue.", "es": "La muerte y la vida están en poder de la lengua."},
    {"reference": "Matteo 28:18-19", "it": "Ogni potere mi è stato dato in cielo e sulla terra. Andate dunque.", "en": "All authority in heaven and on earth has been given to me. Go therefore.", "es": "Toda potestad me es dada en el cielo y en la tierra. Id, pues."},
    {"reference": "1 Pietro 3:15", "it": "Santificate il Cristo come Signore nei vostri cuori, sempre pronti a rispondere.", "en": "In your hearts honor Christ the Lord as holy, always being prepared to give an answer.", "es": "Santificad a Dios el Señor en vuestros corazones, y estad siempre preparados para responder."},
    {"reference": "Salmi 119:165", "it": "Grande pace hanno quelli che amano la tua legge.", "en": "Great peace have those who love your law.", "es": "Mucha paz tienen los que aman tu ley."},
    {"reference": "Giovanni 13:17", "it": "Se sapete queste cose, siete beati se le fate.", "en": "If you know these things, blessed are you if you do them.", "es": "Si sabéis estas cosas, bienaventurados seréis si las hiciereis."},
    {"reference": "Efesini 5:20", "it": "Rendendo continuamente grazie per ogni cosa a Dio Padre.", "en": "Giving thanks always and for everything to God the Father.", "es": "Dando siempre gracias por todo al Dios y Padre."},
    {"reference": "Salmi 20:7", "it": "Gli uni confidano nei carri, gli altri nei cavalli; ma noi invochiamo il nome del SIGNORE.", "en": "Some trust in chariots and some in horses, but we trust in the name of the LORD our God.", "es": "Estos confían en carros, y aquéllos en caballos; mas nosotros del nombre de Jehová nuestro Dios tendremos memoria."},
    {"reference": "Proverbi 24:16", "it": "Il giusto cade sette volte e si rialza.", "en": "The righteous falls seven times and rises again.", "es": "Siete veces cae el justo, y vuelve a levantarse."},
    # Agosto (213-243)
    {"reference": "Giovanni 9:25", "it": "Una cosa so: che ero cieco e ora ci vedo.", "en": "One thing I do know, that though I was blind, now I see.", "es": "Una cosa sé, que habiendo yo sido ciego, ahora veo."},
    {"reference": "Romani 10:17", "it": "La fede viene dall'udire, e l'udire si ha per mezzo della parola di Cristo.", "en": "Faith comes from hearing, and hearing through the word of Christ.", "es": "La fe es por el oír, y el oír, por la palabra de Dios."},
    {"reference": "Salmi 27:4", "it": "Una cosa ho chiesto al SIGNORE, e questa ricerco: abitare nella casa del SIGNORE tutti i giorni della mia vita.", "en": "One thing have I asked of the LORD: that I may dwell in the house of the LORD all the days of my life.", "es": "Una cosa he demandado a Jehová, ésta buscaré; que esté yo en la casa de Jehová todos los días de mi vida."},
    {"reference": "Matteo 5:4", "it": "Beati quelli che sono afflitti, perché saranno consolati.", "en": "Blessed are those who mourn, for they shall be comforted.", "es": "Bienaventurados los que lloran, porque ellos recibirán consolación."},
    {"reference": "Isaia 26:4", "it": "Confidate per sempre nel SIGNORE, perché il SIGNORE, sì il SIGNORE, è la roccia eterna.", "en": "Trust in the LORD forever, for the LORD GOD is an everlasting rock.", "es": "Confiad en Jehová perpetuamente, porque en Jehová el Señor está la fortaleza de los siglos."},
    {"reference": "Salmi 29:11", "it": "Il SIGNORE dà forza al suo popolo, il SIGNORE benedice il suo popolo dandogli pace.", "en": "May the LORD give strength to his people! May the LORD bless his people with peace!", "es": "Jehová dará poder a su pueblo; Jehová bendecirá a su pueblo con paz."},
    {"reference": "Giovanni 11:35", "it": "Gesù pianse.", "en": "Jesus wept.", "es": "Jesús lloró."},
    {"reference": "Filippesi 4:19", "it": "Il mio Dio provvederà a ogni vostro bisogno secondo la sua ricchezza.", "en": "My God will supply every need of yours according to his riches in glory.", "es": "Mi Dios, pues, suplirá todo lo que os falta conforme a sus riquezas en gloria."},
    {"reference": "Salmi 34:17-18", "it": "I giusti gridano e il SIGNORE li ascolta.", "en": "When the righteous cry for help, the LORD hears.", "es": "Claman los justos, y Jehová oye."},
    {"reference": "Proverbi 13:20", "it": "Chi cammina con i saggi diventa saggio.", "en": "Whoever walks with the wise becomes wise.", "es": "El que anda con sabios, sabio será."},
    {"reference": "Matteo 17:20", "it": "Se avete fede quanto un granello di senape, potrete dire a questo monte: Spostati.", "en": "If you have faith like a grain of mustard seed, you will say to this mountain, 'Move.'", "es": "Si tuviereis fe como un grano de mostaza, diréis a este monte: Pásate de aquí."},
    {"reference": "Romani 8:37", "it": "In tutte queste cose, noi siamo più che vincitori.", "en": "In all these things we are more than conquerors.", "es": "En todas estas cosas somos más que vencedores."},
    {"reference": "Salmi 17:8", "it": "Proteggimi come la pupilla dell'occhio, nascondimi all'ombra delle tue ali.", "en": "Keep me as the apple of your eye; hide me in the shadow of your wings.", "es": "Guárdame como a la niña de tus ojos; escóndeme bajo la sombra de tus alas."},
    {"reference": "Giovanni 14:21", "it": "Chi mi ama sarà amato dal Padre mio, e io lo amerò e mi manifesterò a lui.", "en": "Whoever loves me will be loved by my Father, and I will love him and manifest myself to him.", "es": "El que me ama, será amado por mi Padre, y yo le amaré, y me manifestaré a él."},
    {"reference": "1 Corinzi 1:18", "it": "La parola della croce è potenza di Dio per noi che siamo salvati.", "en": "The word of the cross is the power of God to us who are being saved.", "es": "La palabra de la cruz es poder de Dios para los que se salvan."},
    {"reference": "Salmi 37:7", "it": "Sta' in silenzio davanti al SIGNORE, e aspettalo.", "en": "Be still before the LORD and wait patiently for him.", "es": "Guarda silencio ante Jehová, y espera en él."},
    {"reference": "Proverbi 2:6", "it": "Il SIGNORE dà la sapienza; dalla sua bocca provengono la scienza e l'intelligenza.", "en": "The LORD gives wisdom; from his mouth come knowledge and understanding.", "es": "Porque Jehová da la sabiduría, y de su boca viene el conocimiento y la inteligencia."},
    {"reference": "Matteo 6:34", "it": "Non siate dunque in ansia per il domani.", "en": "Do not be anxious about tomorrow.", "es": "No os afanéis por el día de mañana."},
    {"reference": "Isaia 46:4", "it": "Fino alla vostra vecchiaia io sarò lo stesso.", "en": "Even to your old age I am he.", "es": "Hasta vuestra vejez yo mismo."},
    {"reference": "Salmi 40:5", "it": "SIGNORE, mio Dio, le tue meraviglie e i tuoi pensieri sono innumerevoli.", "en": "O LORD my God, your wondrous deeds and thoughts toward us are countless.", "es": "Has aumentado, oh Jehová Dios mío, tus maravillas y tus pensamientos."},
    {"reference": "Giovanni 15:11", "it": "Vi ho detto queste cose, affinché la mia gioia sia in voi e la vostra gioia sia completa.", "en": "These things I have spoken to you, that my joy may be in you, and that your joy may be full.", "es": "Estas cosas os he hablado, para que mi gozo esté en vosotros, y vuestro gozo sea cumplido."},
    {"reference": "Romani 11:33", "it": "Oh, la profondità della ricchezza, della sapienza e della scienza di Dio!", "en": "Oh, the depth of the riches and wisdom and knowledge of God!", "es": "¡Oh profundidad de las riquezas de la sabiduría y de la ciencia de Dios!"},
    {"reference": "Salmi 86:11", "it": "Insegnami, o SIGNORE, la tua via; io camminerò nella tua verità.", "en": "Teach me your way, O LORD, that I may walk in your truth.", "es": "Enséñame, oh Jehová, tu camino; caminaré yo en tu verdad."},
    {"reference": "Proverbi 21:21", "it": "Chi ricerca la giustizia e la bontà troverà vita, giustizia e gloria.", "en": "Whoever pursues righteousness and kindness will find life.", "es": "El que sigue la justicia y la misericordia hallará la vida."},
    {"reference": "Matteo 5:16", "it": "Così risplenda la vostra luce davanti agli uomini.", "en": "Let your light shine before others.", "es": "Así alumbre vuestra luz delante de los hombres."},
    {"reference": "1 Giovanni 2:17", "it": "Il mondo passa con la sua concupiscenza; ma chi fa la volontà di Dio rimane in eterno.", "en": "The world is passing away, but whoever does the will of God abides forever.", "es": "El mundo pasa, pero el que hace la voluntad de Dios permanece para siempre."},
    {"reference": "Salmi 13:5-6", "it": "Ma io confido nella tua bontà; il mio cuore gioirà per la tua salvezza.", "en": "But I have trusted in your steadfast love; my heart shall rejoice in your salvation.", "es": "Mas yo en tu misericordia he confiado; mi corazón se alegrará en tu salvación."},
    {"reference": "Giovanni 17:3", "it": "Questa è la vita eterna: che conoscano te, il solo vero Dio.", "en": "This is eternal life, that they know you, the only true God.", "es": "Esta es la vida eterna: que te conozcan a ti, el único Dios verdadero."},
    {"reference": "Efesini 4:2-3", "it": "Con ogni umiltà e mansuetudine, con pazienza, sopportandovi gli uni gli altri.", "en": "With all humility and gentleness, with patience, bearing with one another.", "es": "Con toda humildad y mansedumbre, soportándoos con paciencia los unos a los otros."},
    {"reference": "Salmi 3:3", "it": "Ma tu, o SIGNORE, sei uno scudo attorno a me, sei la mia gloria.", "en": "But you, O LORD, are a shield about me, my glory.", "es": "Mas tú, Jehová, eres escudo alrededor de mí; mi gloria."},
    {"reference": "Proverbi 29:25", "it": "La paura degli uomini è una trappola, ma chi confida nel SIGNORE è al sicuro.", "en": "The fear of man lays a snare, but whoever trusts in the LORD is safe.", "es": "El temor del hombre pondrá lazo; mas el que confía en Jehová será exaltado."},
    # Settembre (244-273)
    {"reference": "Giovanni 4:24", "it": "Dio è Spirito; e quelli che lo adorano devono adorarlo in spirito e verità.", "en": "God is spirit, and those who worship him must worship in spirit and truth.", "es": "Dios es Espíritu; y los que le adoran, en espíritu y en verdad es necesario que adoren."},
    {"reference": "Romani 8:26", "it": "Lo Spirito viene in aiuto alla nostra debolezza.", "en": "The Spirit helps us in our weakness.", "es": "El Espíritu nos ayuda en nuestra debilidad."},
    {"reference": "Salmi 143:10", "it": "Insegnami a fare la tua volontà, perché tu sei il mio Dio.", "en": "Teach me to do your will, for you are my God.", "es": "Enséñame a hacer tu voluntad, porque tú eres mi Dios."},
    {"reference": "Matteo 5:7", "it": "Beati i misericordiosi, perché a loro misericordia sarà fatta.", "en": "Blessed are the merciful, for they shall receive mercy.", "es": "Bienaventurados los misericordiosos, porque ellos alcanzarán misericordia."},
    {"reference": "Isaia 43:19", "it": "Ecco, io sto per fare una cosa nuova; la vedete germogliare?", "en": "Behold, I am doing a new thing; do you not perceive it?", "es": "He aquí que yo hago cosa nueva; pronto saldrá a luz."},
    {"reference": "Salmi 28:7", "it": "Il SIGNORE è la mia forza e il mio scudo; in lui si è confidato il mio cuore.", "en": "The LORD is my strength and my shield; in him my heart trusts.", "es": "Jehová es mi fortaleza y mi escudo; en él confió mi corazón."},
    {"reference": "Giovanni 14:16-17", "it": "Io pregherò il Padre, ed Egli vi darà un altro Consolatore.", "en": "I will ask the Father, and he will give you another Helper.", "es": "Yo rogaré al Padre, y os dará otro Consolador."},
    {"reference": "Filippesi 2:3-4", "it": "Non fate nulla per spirito di parte, ma ciascuno di voi, con umiltà, stimi gli altri superiori a sé stesso.", "en": "In humility count others more significant than yourselves.", "es": "Estimando cada uno a los demás como superiores a él mismo."},
    {"reference": "Salmi 59:16", "it": "Io canterò la tua forza, e al mattino celebrerò la tua grazia.", "en": "I will sing of your strength; I will sing aloud of your steadfast love in the morning.", "es": "Yo cantaré de tu poder, y alabaré de mañana tu misericordia."},
    {"reference": "Proverbi 4:7", "it": "Il principio della saggezza è: acquista la saggezza.", "en": "The beginning of wisdom is this: Get wisdom.", "es": "Sabiduría ante todo; adquiere sabiduría."},
    {"reference": "Matteo 21:22", "it": "Tutte le cose che domanderete in preghiera, se avete fede, le otterrete.", "en": "Whatever you ask in prayer, you will receive, if you have faith.", "es": "Todo lo que pidiereis en oración, creyendo, lo recibiréis."},
    {"reference": "Romani 8:6", "it": "La mentalità dello Spirito è vita e pace.", "en": "To set the mind on the Spirit is life and peace.", "es": "El ocuparse del Espíritu es vida y paz."},
    {"reference": "Salmi 89:1", "it": "Io canterò per sempre le grazie del SIGNORE.", "en": "I will sing of the steadfast love of the LORD, forever.", "es": "Las misericordias de Jehová cantaré perpetuamente."},
    {"reference": "Giovanni 15:16", "it": "Non siete voi che avete scelto me, ma sono io che ho scelto voi.", "en": "You did not choose me, but I chose you.", "es": "No me elegisteis vosotros a mí, sino que yo os elegí a vosotros."},
    {"reference": "1 Corinzi 15:55-57", "it": "O morte, dov'è la tua vittoria? Ringraziato sia Dio che ci dà la vittoria.", "en": "O death, where is your victory? Thanks be to God, who gives us the victory.", "es": "¿Dónde está, oh muerte, tu aguijón? Gracias sean dadas a Dios, que nos da la victoria."},
    {"reference": "Salmi 97:11", "it": "La luce è spuntata per il giusto, e la gioia per quelli che sono retti di cuore.", "en": "Light is sown for the righteous, and joy for the upright in heart.", "es": "Luz está satisfecha para el justo, y alegría para los rectos de corazón."},
    {"reference": "Proverbi 16:32", "it": "Chi è lento all'ira vale più di un prode guerriero.", "en": "Whoever is slow to anger is better than the mighty.", "es": "Mejor es el que tarda en airarse que el fuerte."},
    {"reference": "Matteo 7:24", "it": "Chiunque ascolta queste mie parole e le mette in pratica sarà paragonato a un uomo avveduto che ha costruito la sua casa sulla roccia.", "en": "Everyone who hears these words of mine and does them will be like a wise man who built his house on the rock.", "es": "Cualquiera que me oye estas palabras, y las hace, le compararé a un hombre prudente, que edificó su casa sobre la roca."},
    {"reference": "Isaia 40:28", "it": "Non lo sai tu? Non l'hai sentito? Il SIGNORE è Dio eterno, il creatore degli estremi confini della terra.", "en": "Have you not known? Have you not heard? The LORD is the everlasting God, the Creator of the ends of the earth.", "es": "¿No has sabido, no has oído que el Dios eterno es Jehová, el cual creó los confines de la tierra?"},
    {"reference": "Salmi 51:12", "it": "Rendimi la gioia della tua salvezza e sostienimi con uno spirito volenteroso.", "en": "Restore to me the joy of your salvation, and uphold me with a willing spirit.", "es": "Vuélveme el gozo de tu salvación, y espíritu noble me sustente."},
    {"reference": "Giovanni 6:51", "it": "Io sono il pane vivente, che è disceso dal cielo.", "en": "I am the living bread that came down from heaven.", "es": "Yo soy el pan vivo que descendió del cielo."},
    {"reference": "Romani 6:11", "it": "Consideratevi morti al peccato, ma viventi a Dio, in Cristo Gesù.", "en": "Consider yourselves dead to sin and alive to God in Christ Jesus.", "es": "Consideraos muertos al pecado, pero vivos para Dios en Cristo Jesús."},
    {"reference": "Salmi 119:133", "it": "Dirigi i miei passi secondo la tua parola.", "en": "Keep steady my steps according to your promise.", "es": "Ordena mis pasos con tu palabra."},
    {"reference": "Proverbi 28:13", "it": "Chi copre le sue trasgressioni non prospererà, ma chi le confessa e le abbandona otterrà misericordia.", "en": "Whoever conceals his transgressions will not prosper, but he who confesses and forsakes them will obtain mercy.", "es": "El que encubre sus pecados no prosperará; mas el que los confiesa y se aparta alcanzará misericordia."},
    {"reference": "Matteo 10:29-30", "it": "Neppure un passero cade a terra senza che il Padre vostro lo voglia. Perfino i capelli del vostro capo sono tutti contati.", "en": "Not one sparrow will fall to the ground apart from your Father. Even the hairs of your head are all numbered.", "es": "Ni un pajarillo cae a tierra sin vuestro Padre. Pues aun vuestros cabellos están todos contados."},
    {"reference": "1 Giovanni 4:16", "it": "Noi abbiamo conosciuto l'amore che Dio ha per noi, e vi abbiamo creduto. Dio è amore.", "en": "We have come to know and to believe the love that God has for us. God is love.", "es": "Hemos conocido y creído el amor que Dios tiene para con nosotros. Dios es amor."},
    {"reference": "Salmi 54:4", "it": "Ecco, Dio è il mio aiutatore; il Signore è colui che sostiene l'anima mia.", "en": "Behold, God is my helper; the Lord is the upholder of my life.", "es": "He aquí, Dios es el que me ayuda; el Señor está con los que sostienen mi vida."},
    {"reference": "Giovanni 8:31-32", "it": "Se perseverate nella mia parola, siete veramente miei discepoli.", "en": "If you abide in my word, you are truly my disciples.", "es": "Si vosotros permaneciereis en mi palabra, seréis verdaderamente mis discípulos."},
    {"reference": "Efesini 3:17-18", "it": "Che Cristo abiti per mezzo della fede nei vostri cuori.", "en": "That Christ may dwell in your hearts through faith.", "es": "Para que habite Cristo por la fe en vuestros corazones."},
    {"reference": "Salmi 67:1-2", "it": "Dio abbia pietà di noi e ci benedica, faccia risplendere il suo volto su di noi.", "en": "May God be gracious to us and bless us and make his face to shine upon us.", "es": "Dios tenga misericordia de nosotros, y nos bendiga; haga resplandecer su rostro sobre nosotros."},
    # Ottobre (274-304)
    {"reference": "Giovanni 1:1", "it": "Nel principio era la Parola, la Parola era con Dio, e la Parola era Dio.", "en": "In the beginning was the Word, and the Word was with God, and the Word was God.", "es": "En el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios."},
    {"reference": "Romani 8:11", "it": "Lo Spirito di colui che ha risuscitato Gesù dai morti abita in voi.", "en": "The Spirit of him who raised Jesus from the dead dwells in you.", "es": "El Espíritu de aquel que levantó de los muertos a Jesús mora en vosotros."},
    {"reference": "Salmi 118:14", "it": "Il SIGNORE è la mia forza e il mio cantico; egli è stato la mia salvezza.", "en": "The LORD is my strength and my song; he has become my salvation.", "es": "Mi fortaleza y mi cántico es JAH, y él me ha sido por salvación."},
    {"reference": "Matteo 6:21", "it": "Là dov'è il tuo tesoro, là sarà anche il tuo cuore.", "en": "Where your treasure is, there your heart will be also.", "es": "Donde esté vuestro tesoro, allí estará también vuestro corazón."},
    {"reference": "Isaia 64:8", "it": "SIGNORE, tu sei nostro Padre; noi siamo l'argilla e tu colui che ci plasma.", "en": "O LORD, you are our Father; we are the clay, and you are our potter.", "es": "Tú eres nuestro padre; nosotros barro, y tú el que nos formaste."},
    {"reference": "Salmi 61:2", "it": "Dall'estremità della terra io grido a te; quando il cuore mi viene meno, guidami alla roccia che è troppo alta per me.", "en": "From the end of the earth I call to you when my heart is faint. Lead me to the rock that is higher than I.", "es": "Desde el cabo de la tierra clamaré a ti, cuando mi corazón desmayare. Llévame a la roca que es más alta que yo."},
    {"reference": "Giovanni 5:39", "it": "Le Scritture sono quelle che rendono testimonianza di me.", "en": "The Scriptures bear witness about me.", "es": "Las Escrituras dan testimonio de mí."},
    {"reference": "Filippesi 1:21", "it": "Per me infatti il vivere è Cristo e il morire guadagno.", "en": "For to me to live is Christ, and to die is gain.", "es": "Porque para mí el vivir es Cristo, y el morir es ganancia."},
    {"reference": "Salmi 31:14-15", "it": "Ma io confido in te, o SIGNORE! Io dico: Tu sei il mio Dio. I miei giorni sono nelle tue mani.", "en": "But I trust in you, O LORD; I say, 'You are my God.' My times are in your hand.", "es": "Mas yo en ti confié, oh Jehová; dije: Tú eres mi Dios. En tu mano están mis tiempos."},
    {"reference": "Proverbi 1:7", "it": "Il timore del SIGNORE è il principio della scienza.", "en": "The fear of the LORD is the beginning of knowledge.", "es": "El principio de la sabiduría es el temor de Jehová."},
    {"reference": "Matteo 11:30", "it": "Il mio giogo è dolce e il mio carico è leggero.", "en": "My yoke is easy, and my burden is light.", "es": "Mi yugo es fácil, y ligera mi carga."},
    {"reference": "Romani 12:21", "it": "Non lasciarti vincere dal male, ma vinci il male con il bene.", "en": "Do not be overcome by evil, but overcome evil with good.", "es": "No seas vencido de lo malo, sino vence con el bien el mal."},
    {"reference": "Salmi 139:23-24", "it": "Esaminami, o Dio, e conosci il mio cuore. Mettimi alla prova e conosci i miei pensieri.", "en": "Search me, O God, and know my heart! Try me and know my thoughts!", "es": "Examíname, oh Dios, y conoce mi corazón; pruébame y conoce mis pensamientos."},
    {"reference": "Giovanni 15:4", "it": "Dimorate in me, e io dimorerò in voi.", "en": "Abide in me, and I in you.", "es": "Permaneced en mí, y yo en vosotros."},
    {"reference": "1 Corinzi 3:16", "it": "Non sapete che siete il tempio di Dio e che lo Spirito di Dio abita in voi?", "en": "Do you not know that you are God's temple and that God's Spirit dwells in you?", "es": "¿No sabéis que sois templo de Dios, y que el Espíritu de Dios mora en vosotros?"},
    {"reference": "Salmi 119:114", "it": "Tu sei il mio rifugio e il mio scudo; io spero nella tua parola.", "en": "You are my hiding place and my shield; I hope in your word.", "es": "Mi escondedero y mi escudo eres tú; en tu palabra he esperado."},
    {"reference": "Proverbi 19:11", "it": "Il senno rende l'uomo lento all'ira, ed egli si fa un onore di passare sopra le offese.", "en": "Good sense makes one slow to anger, and it is his glory to overlook an offense.", "es": "La cordura del hombre detiene su furor, y su honra es pasar por alto la ofensa."},
    {"reference": "Matteo 7:8", "it": "Chiunque chiede riceve, chi cerca trova.", "en": "Everyone who asks receives, and the one who seeks finds.", "es": "Todo aquel que pide, recibe; y el que busca, halla."},
    {"reference": "Isaia 41:13", "it": "Io, il SIGNORE, il tuo Dio, ti tengo per la mano destra e ti dico: Non temere, io ti aiuto!", "en": "I, the LORD your God, hold your right hand; it is I who say to you, Fear not, I am the one who helps you.", "es": "Yo Jehová soy tu Dios, quien te sostiene de tu mano derecha, y te dice: No temas, yo te ayudo."},
    {"reference": "Salmi 31:3", "it": "Tu sei la mia rocca e la mia fortezza; per amore del tuo nome guidami e conducimi.", "en": "You are indeed my rock and my fortress; and for your name's sake you lead me and guide me.", "es": "Porque tú eres mi roca y mi castillo; por tu nombre me guiarás y me encaminarás."},
    {"reference": "Giovanni 14:23", "it": "Se uno mi ama, osserverà la mia parola.", "en": "If anyone loves me, he will keep my word.", "es": "El que me ama, mi palabra guardará."},
    {"reference": "Romani 15:1", "it": "Noi che siamo forti, dobbiamo sopportare le debolezze di quelli che forti non sono.", "en": "We who are strong have an obligation to bear with the failings of the weak.", "es": "Los que somos fuertes debemos soportar las flaquezas de los débiles."},
    {"reference": "Salmi 23:3", "it": "Egli mi ristora l'anima, mi conduce per sentieri di giustizia.", "en": "He restores my soul. He leads me in paths of righteousness.", "es": "Confortará mi alma; me guiará por sendas de justicia."},
    {"reference": "Proverbi 3:13", "it": "Beato l'uomo che ha trovato la sapienza, e l'uomo che ottiene l'intelligenza!", "en": "Blessed is the one who finds wisdom, and the one who gets understanding.", "es": "Bienaventurado el hombre que halla la sabiduría."},
    {"reference": "Matteo 14:27", "it": "Coraggio, sono io; non abbiate paura!", "en": "Take heart; it is I. Do not be afraid.", "es": "¡Tened ánimo; yo soy, no temáis!"},
    {"reference": "1 Giovanni 5:4", "it": "Tutto quello che è nato da Dio vince il mondo; e questa è la vittoria che ha vinto il mondo: la nostra fede.", "en": "Everyone who has been born of God overcomes the world. And this is the victory that has overcome the world—our faith.", "es": "Todo lo que es nacido de Dios vence al mundo; y esta es la victoria que ha vencido al mundo, nuestra fe."},
    {"reference": "Salmi 145:3", "it": "Grande è il SIGNORE e degno di lode; la sua grandezza non si può misurare.", "en": "Great is the LORD, and greatly to be praised, and his greatness is unsearchable.", "es": "Grande es Jehová, y digno de suprema alabanza; y su grandeza es inescrutable."},
    {"reference": "Giovanni 10:14", "it": "Io sono il buon pastore, e conosco le mie pecore e le mie pecore conoscono me.", "en": "I am the good shepherd. I know my own and my own know me.", "es": "Yo soy el buen pastor; y conozco mis ovejas, y las mías me conocen."},
    {"reference": "Efesini 6:11", "it": "Rivestitevi della completa armatura di Dio.", "en": "Put on the whole armor of God.", "es": "Vestíos de toda la armadura de Dios."},
    {"reference": "Salmi 85:10", "it": "Grazia e verità si sono incontrate, giustizia e pace si sono baciate.", "en": "Steadfast love and faithfulness meet; righteousness and peace kiss each other.", "es": "La misericordia y la verdad se encontraron; la justicia y la paz se besaron."},
    {"reference": "Proverbi 15:33", "it": "Il timore del SIGNORE è scuola di sapienza.", "en": "The fear of the LORD is instruction in wisdom.", "es": "El temor de Jehová es enseñanza de sabiduría."},
    # Novembre (305-334)
    {"reference": "Giovanni 17:21", "it": "Che siano tutti uno; e come tu, o Padre, sei in me e io sono in te.", "en": "That they may all be one, just as you, Father, are in me, and I in you.", "es": "Para que todos sean uno; como tú, oh Padre, en mí, y yo en ti."},
    {"reference": "Romani 12:9-10", "it": "L'amore sia senza ipocrisia. Quanto all'amore fraterno, siate pieni di affetto gli uni per gli altri.", "en": "Let love be genuine. Love one another with brotherly affection.", "es": "El amor sea sin fingimiento. Amaos los unos a los otros con amor fraternal."},
    {"reference": "Salmi 106:1", "it": "Alleluia. Celebrate il SIGNORE, perché egli è buono.", "en": "Praise the LORD! Oh give thanks to the LORD, for he is good.", "es": "Aleluya. Alabad a Jehová, porque él es bueno."},
    {"reference": "Matteo 5:13", "it": "Voi siete il sale della terra.", "en": "You are the salt of the earth.", "es": "Vosotros sois la sal de la tierra."},
    {"reference": "Isaia 40:8", "it": "L'erba si secca, il fiore appassisce, ma la parola del nostro Dio dura per sempre.", "en": "The grass withers, the flower fades, but the word of our God will stand forever.", "es": "Sécase la hierba, marchítase la flor; mas la palabra del Dios nuestro permanece para siempre."},
    {"reference": "Salmi 119:71", "it": "È stato un bene per me l'essere afflitto, perché imparassi i tuoi statuti.", "en": "It is good for me that I was afflicted, that I might learn your statutes.", "es": "Bueno me es haber sido humillado, para que aprenda tus estatutos."},
    {"reference": "Giovanni 13:35", "it": "Da questo conosceranno tutti che siete miei discepoli, se avete amore gli uni per gli altri.", "en": "By this all people will know that you are my disciples, if you have love for one another.", "es": "En esto conocerán todos que sois mis discípulos, si tuviereis amor los unos con los otros."},
    {"reference": "Filippesi 4:11", "it": "Ho imparato ad accontentarmi dello stato in cui mi trovo.", "en": "I have learned in whatever situation I am to be content.", "es": "He aprendido a contentarme, cualquiera que sea mi situación."},
    {"reference": "Salmi 127:1", "it": "Se il SIGNORE non costruisce la casa, invano si affaticano i costruttori.", "en": "Unless the LORD builds the house, those who build it labor in vain.", "es": "Si Jehová no edificare la casa, en vano trabajan los que la edifican."},
    {"reference": "Proverbi 6:20-22", "it": "Figlio mio, osserva i precetti di tuo padre e non trascurare gli insegnamenti di tua madre.", "en": "My son, keep your father's commandment, and forsake not your mother's teaching.", "es": "Guarda, hijo mío, el mandamiento de tu padre, y no dejes la enseñanza de tu madre."},
    {"reference": "Matteo 20:28", "it": "Il Figlio dell'uomo non è venuto per essere servito, ma per servire.", "en": "The Son of Man came not to be served but to serve.", "es": "El Hijo del Hombre no vino para ser servido, sino para servir."},
    {"reference": "Romani 5:3-4", "it": "La tribolazione produce pazienza, la pazienza esperienza, e l'esperienza speranza.", "en": "Suffering produces endurance, and endurance produces character, and character produces hope.", "es": "La tribulación produce paciencia; y la paciencia, prueba; y la prueba, esperanza."},
    {"reference": "Salmi 91:4", "it": "Egli ti coprirà con le sue penne e sotto le sue ali troverai rifugio.", "en": "He will cover you with his pinions, and under his wings you will find refuge.", "es": "Con sus plumas te cubrirá, y debajo de sus alas estarás seguro."},
    {"reference": "Giovanni 11:40", "it": "Non ti ho detto che se credi, vedrai la gloria di Dio?", "en": "Did I not tell you that if you believed you would see the glory of God?", "es": "¿No te he dicho que si crees, verás la gloria de Dios?"},
    {"reference": "1 Corinzi 10:31", "it": "Sia dunque che mangiate, sia che beviate, sia che facciate qualche altra cosa, fate tutto alla gloria di Dio.", "en": "Whether you eat or drink, or whatever you do, do all to the glory of God.", "es": "Si coméis o bebéis, o hacéis otra cosa, hacedlo todo para la gloria de Dios."},
    {"reference": "Salmi 19:14", "it": "Siano graditi davanti a te le parole della mia bocca e la meditazione del mio cuore.", "en": "Let the words of my mouth and the meditation of my heart be acceptable in your sight.", "es": "Sean gratos los dichos de mi boca y la meditación de mi corazón delante de ti."},
    {"reference": "Proverbi 25:21-22", "it": "Se il tuo nemico ha fame, dagli del pane da mangiare.", "en": "If your enemy is hungry, give him bread to eat.", "es": "Si el que te aborrece tuviere hambre, dale de comer pan."},
    {"reference": "Matteo 12:36-37", "it": "Di ogni parola oziosa che gli uomini avranno detta, dovranno rendere conto nel giorno del giudizio.", "en": "On the day of judgment people will give account for every careless word they speak.", "es": "De toda palabra ociosa que hablen los hombres, de ella darán cuenta en el día del juicio."},
    {"reference": "Isaia 48:17", "it": "Io sono il SIGNORE, il tuo Dio, che ti insegna per il tuo bene.", "en": "I am the LORD your God, who teaches you to profit.", "es": "Yo soy Jehová Dios tuyo, que te enseña provechosamente."},
    {"reference": "Salmi 34:10", "it": "I leoncelli soffrono la fame, ma quelli che cercano il SIGNORE non mancano di nulla.", "en": "The young lions suffer want and hunger; but those who seek the LORD lack no good thing.", "es": "Los leoncillos necesitan, y tienen hambre; pero los que buscan a Jehová no tendrán falta de ningún bien."},
    {"reference": "Giovanni 4:34", "it": "Il mio cibo è fare la volontà di colui che mi ha mandato.", "en": "My food is to do the will of him who sent me.", "es": "Mi comida es que haga la voluntad del que me envió."},
    {"reference": "Romani 13:8", "it": "Non abbiate altro debito con nessuno, se non di amarvi gli uni gli altri.", "en": "Owe no one anything, except to love each other.", "es": "No debáis a nadie nada, sino el amaros unos a otros."},
    {"reference": "Salmi 130:5-6", "it": "Io aspetto il SIGNORE, l'anima mia lo aspetta; io spero nella sua parola.", "en": "I wait for the LORD, my soul waits, and in his word I hope.", "es": "Esperé yo a Jehová, esperó mi alma; en su palabra he esperado."},
    {"reference": "Proverbi 22:1", "it": "La buona reputazione è da preferirsi alle molte ricchezze.", "en": "A good name is to be chosen rather than great riches.", "es": "De más estima es el buen nombre que las muchas riquezas."},
    {"reference": "Matteo 18:3", "it": "Se non cambiate e non diventate come i bambini, non entrerete nel regno dei cieli.", "en": "Unless you turn and become like children, you will never enter the kingdom of heaven.", "es": "Si no os volvéis y os hacéis como niños, no entraréis en el reino de los cielos."},
    {"reference": "1 Giovanni 3:18", "it": "Figlioli, non amiamo a parole né con la lingua, ma con i fatti e in verità.", "en": "Little children, let us not love in word or talk but in deed and in truth.", "es": "Hijitos míos, no amemos de palabra ni de lengua, sino de hecho y en verdad."},
    {"reference": "Salmi 138:3", "it": "Nel giorno che ho gridato tu mi hai risposto; mi hai reso forte.", "en": "On the day I called, you answered me; my strength of soul you increased.", "es": "El día que clamé, me respondiste; me fortaleciste con vigor en mi alma."},
    {"reference": "Giovanni 6:40", "it": "Chiunque contempla il Figlio e crede in lui, abbia vita eterna.", "en": "Everyone who looks on the Son and believes in him should have eternal life.", "es": "Todo aquel que ve al Hijo, y cree en él, tenga vida eterna."},
    {"reference": "Efesini 4:29", "it": "Nessuna cattiva parola esca dalla vostra bocca; ma se ne avete qualcuna buona, che edifichi secondo il bisogno, ditela.", "en": "Let no corrupting talk come out of your mouths, but only such as is good for building up.", "es": "Ninguna palabra corrompida salga de vuestra boca, sino la que sea buena para la necesaria edificación."},
    {"reference": "Salmi 111:1", "it": "Alleluia. Io celebrerò il SIGNORE con tutto il cuore.", "en": "Praise the LORD! I will give thanks to the LORD with my whole heart.", "es": "Aleluya. Alabaré a Jehová con todo el corazón."},
    # Dicembre (335-365)
    {"reference": "Giovanni 1:4", "it": "In lei era la vita, e la vita era la luce degli uomini.", "en": "In him was life, and the life was the light of men.", "es": "En él estaba la vida, y la vida era la luz de los hombres."},
    {"reference": "Romani 11:36", "it": "Da lui, per mezzo di lui e per lui sono tutte le cose. A lui sia la gloria in eterno. Amen.", "en": "For from him and through him and to him are all things. To him be glory forever. Amen.", "es": "Porque de él, y por él, y para él, son todas las cosas. A él sea la gloria por los siglos. Amén."},
    {"reference": "Salmi 146:5", "it": "Beato colui che ha per aiuto il Dio di Giacobbe, che spera nel SIGNORE, suo Dio.", "en": "Blessed is he whose help is the God of Jacob, whose hope is in the LORD his God.", "es": "Bienaventurado aquel cuyo ayudador es el Dios de Jacob, cuya esperanza está en Jehová su Dios."},
    {"reference": "Matteo 1:23", "it": "La vergine sarà incinta e partorirà un figlio, e gli sarà posto nome Emanuele.", "en": "The virgin shall conceive and bear a son, and they shall call his name Immanuel.", "es": "La virgen concebirá y dará a luz un hijo, y llamarás su nombre Emanuel."},
    {"reference": "Isaia 9:5", "it": "Un bambino ci è nato, un figlio ci è stato dato.", "en": "For to us a child is born, to us a son is given.", "es": "Porque un niño nos es nacido, hijo nos es dado."},
    {"reference": "Salmi 98:1", "it": "Cantate al SIGNORE un cantico nuovo, perché ha fatto cose meravigliose.", "en": "Sing to the LORD a new song, for he has done marvelous things.", "es": "Cantad a Jehová cántico nuevo, porque ha hecho maravillas."},
    {"reference": "Giovanni 1:9", "it": "La vera luce che illumina ogni uomo stava venendo nel mondo.", "en": "The true light, which gives light to everyone, was coming into the world.", "es": "Aquella luz verdadera, que alumbra a todo hombre, venía a este mundo."},
    {"reference": "Filippesi 2:5-6", "it": "Abbiate in voi lo stesso sentimento che è stato anche in Cristo Gesù.", "en": "Have this mind among yourselves, which is yours in Christ Jesus.", "es": "Haya, pues, en vosotros este sentir que hubo también en Cristo Jesús."},
    {"reference": "Salmi 148:1-2", "it": "Alleluia. Lodate il SIGNORE dai cieli, lodatelo nei luoghi altissimi.", "en": "Praise the LORD! Praise the LORD from the heavens; praise him in the heights!", "es": "Aleluya. Alabad a Jehová desde los cielos; alabadle en las alturas."},
    {"reference": "Proverbi 8:35", "it": "Chi mi trova trova la vita, e ottiene favore dal SIGNORE.", "en": "Whoever finds me finds life and obtains favor from the LORD.", "es": "Porque el que me halle, hallará la vida, y alcanzará el favor de Jehová."},
    {"reference": "Matteo 2:10-11", "it": "Quando videro la stella, si rallegrarono di grandissima gioia.", "en": "When they saw the star, they rejoiced exceedingly with great joy.", "es": "Cuando vieron la estrella, se regocijaron con muy grande gozo."},
    {"reference": "Romani 8:32", "it": "Colui che non ha risparmiato il proprio Figlio, ma lo ha dato per noi tutti.", "en": "He who did not spare his own Son but gave him up for us all.", "es": "El que no escatimó ni a su propio Hijo, sino que lo entregó por todos nosotros."},
    {"reference": "Salmi 103:2-3", "it": "Benedici, anima mia, il SIGNORE e non dimenticare nessuno dei suoi benefici.", "en": "Bless the LORD, O my soul, and forget not all his benefits.", "es": "Bendice, alma mía, a Jehová, y no olvides ninguno de sus beneficios."},
    {"reference": "Giovanni 3:17", "it": "Dio non ha mandato suo Figlio nel mondo per giudicare il mondo, ma perché il mondo sia salvato per mezzo di lui.", "en": "God did not send his Son into the world to condemn the world, but to save the world through him.", "es": "Dios no envió a su Hijo al mundo para condenar al mundo, sino para que el mundo sea salvo por él."},
    {"reference": "1 Corinzi 1:30", "it": "Voi siete in Cristo Gesù, che ci è stato fatto da Dio sapienza, giustizia, santificazione e redenzione.", "en": "Because of him you are in Christ Jesus, who became to us wisdom from God.", "es": "Mas por él estáis vosotros en Cristo Jesús, el cual nos ha sido hecho por Dios sabiduría."},
    {"reference": "Salmi 96:2-3", "it": "Cantate al SIGNORE, benedite il suo nome, annunciate di giorno in giorno la sua salvezza.", "en": "Sing to the LORD, bless his name; tell of his salvation from day to day.", "es": "Cantad a Jehová, bendecid su nombre; anunciad de día en día su salvación."},
    {"reference": "Proverbi 9:10", "it": "Il principio della sapienza è il timore del SIGNORE.", "en": "The fear of the LORD is the beginning of wisdom.", "es": "El temor de Jehová es el principio de la sabiduría."},
    {"reference": "Matteo 2:2", "it": "Dov'è il re dei Giudei che è nato? Poiché noi abbiamo visto la sua stella in Oriente.", "en": "Where is he who has been born king of the Jews? For we saw his star when it rose.", "es": "¿Dónde está el rey de los judíos, que ha nacido? Porque su estrella hemos visto en el oriente."},
    {"reference": "Isaia 7:14", "it": "Il Signore stesso vi darà un segno: Ecco, la giovane concepirà, partorirà un figlio.", "en": "The Lord himself will give you a sign. Behold, the virgin shall conceive and bear a son.", "es": "El Señor mismo os dará señal: He aquí que la virgen concebirá, y dará a luz un hijo."},
    {"reference": "Salmi 147:1", "it": "Alleluia. È bello cantare le lodi al nostro Dio; è piacevole e convenevole lodarlo.", "en": "Praise the LORD! For it is good to sing praises to our God.", "es": "Alabad a JAH, porque es bueno cantar salmos a nuestro Dios."},
    {"reference": "Giovanni 1:16", "it": "Dalla sua pienezza noi tutti abbiamo ricevuto grazia su grazia.", "en": "From his fullness we have all received, grace upon grace.", "es": "De su plenitud tomamos todos, y gracia sobre gracia."},
    {"reference": "Romani 6:4", "it": "Affinché, come Cristo è risuscitato dai morti mediante la gloria del Padre, così anche noi camminassimo in novità di vita.", "en": "We too might walk in newness of life.", "es": "A fin de que como Cristo resucitó de los muertos por la gloria del Padre, así también nosotros andemos en vida nueva."},
    {"reference": "Salmi 117:1-2", "it": "Lodate il SIGNORE, voi tutte le nazioni; celebratelo, voi tutti i popoli!", "en": "Praise the LORD, all nations! Extol him, all peoples!", "es": "Alabad a Jehová, naciones todas; pueblos todos, alabadle."},
    {"reference": "Proverbi 16:20", "it": "Chi presta attenzione alla parola se ne troverà bene, e beato chi confida nel SIGNORE!", "en": "Whoever gives thought to the word will discover good, and blessed is he who trusts in the LORD.", "es": "El entendido en la palabra hallará el bien, y el que confía en Jehová es bienaventurado."},
    {"reference": "Matteo 5:11-12", "it": "Beati voi, quando vi insulteranno e vi perseguiteranno. Rallegratevi e giubilate, perché il vostro premio è grande nei cieli.", "en": "Blessed are you when others revile you and persecute you. Rejoice and be glad, for your reward is great in heaven.", "es": "Bienaventurados sois cuando por mi causa os vituperen y os persigan. Gozaos y alegraos, porque vuestro galardón es grande en los cielos."},
    {"reference": "1 Giovanni 4:9", "it": "In questo si è manifestato l'amore di Dio per noi: Dio ha mandato il suo Figlio unigenito nel mondo.", "en": "In this the love of God was made manifest: that God sent his only Son into the world.", "es": "En esto se mostró el amor de Dios para con nosotros, en que Dios envió a su Hijo unigénito al mundo."},
    {"reference": "Salmi 149:1", "it": "Alleluia. Cantate al SIGNORE un cantico nuovo, cantate la sua lode nell'assemblea dei fedeli.", "en": "Praise the LORD! Sing to the LORD a new song, his praise in the assembly of the godly!", "es": "Aleluya. Cantad a Jehová cántico nuevo; su alabanza sea en la congregación de los santos."},
    {"reference": "Giovanni 1:29", "it": "Ecco l'Agnello di Dio, che toglie il peccato del mondo!", "en": "Behold, the Lamb of God, who takes away the sin of the world!", "es": "He aquí el Cordero de Dios, que quita el pecado del mundo."},
    {"reference": "Efesini 1:3", "it": "Benedetto sia il Dio e Padre del nostro Signore Gesù Cristo, che ci ha benedetti di ogni benedizione spirituale.", "en": "Blessed be the God and Father of our Lord Jesus Christ, who has blessed us with every spiritual blessing.", "es": "Bendito sea el Dios y Padre de nuestro Señor Jesucristo, que nos bendijo con toda bendición espiritual."},
    {"reference": "Salmi 100:1-2", "it": "Acclamate il SIGNORE, o abitanti di tutta la terra! Servite il SIGNORE con letizia.", "en": "Make a joyful noise to the LORD, all the earth! Serve the LORD with gladness.", "es": "Cantad alegres a Dios, habitantes de toda la tierra. Servid a Jehová con alegría."},
    {"reference": "Apocalisse 22:20-21", "it": "Colui che attesta queste cose, dice: Sì, vengo presto! Amen! Vieni, Signore Gesù! La grazia del Signore Gesù sia con tutti.", "en": "He who testifies to these things says, 'Surely I am coming soon.' Amen. Come, Lord Jesus! The grace of the Lord Jesus be with all.", "es": "El que da testimonio de estas cosas dice: Ciertamente vengo en breve. Amén; sí, ven, Señor Jesús. La gracia de nuestro Señor Jesucristo sea con todos vosotros. Amén."},
]

def get_daily_verse(day_of_year: int) -> dict:
    """Get the verse for a specific day of the year (1-365)"""
    if day_of_year < 1:
        day_of_year = 1
    index = (day_of_year - 1) % len(DAILY_VERSES_365)
    return DAILY_VERSES_365[index]
